 {id:"c1g_participle",title:"Participiální vazby",type:"grammar",theory:"Participiální vazby (s -ing/-ed) zkracují věty a jsou typické pro formální nebo psaný projev. <b>Having finished</b> the report, she went home. <b>Feeling</b> tired, he went to bed early.",table:[["Typ","Použití","Příklad"],["-ing","současný/aktivní děj","Walking home, I saw..."],["Having + 3. tvar","děj před hlavním dějem","Having finished, she..."],["-ed","pasivní význam","Written in 1990,..."]],items:[["___ tired, she decided to rest.","Feeling",["Feeling","Feel","Felt"],"Cítila se unavená, rozhodla se odpočívat."],["___ his homework, he went out to play.","Having finished",["Having finished","Finishing","Finish"],"Když dokončil úkol, šel si ven hrát."],["___ in 1990, the building is now a museum.","Built",["Built","Building","Build"],"Postavená v roce 1990, budova je nyní muzeem."],["___ the letter, she sealed the envelope.","Having written",["Having written","Writing","Write"],"Když dopis napsala, zalepila obálku."],["Not ___ what to say, he stayed silent.","knowing",["knowing","know","known"],"Nevěděl, co říct, tak zůstal potichu."],["___ by the noise, the baby woke up.","Startled",["Startled","Startling","Startle"],"Vylekané hlukem, dítě se probudilo."],["___ the mistake, she quickly corrected it.","Noticing",["Noticing","Notice","Noticed"],"Když si všimla chyby, rychle ji opravila."],["___ nothing left to say, he left the room.","Having",["Having","Have","Had"],"Když už neměl co dodat, opustil místnost."],["___ from a wealthy family, he never had to work.","Coming",["Coming","Come","Came"],"Pocházel z bohaté rodiny, nikdy nemusel pracovat."],["___ the risks, they decided to invest anyway.","Weighing",["Weighing","Weigh","Weighed"],"Po zvážení rizik se přesto rozhodli investovat."]]},
 {id:"c1g_reportingpassive",title:"Trpný rod v reportáži",type:"grammar",theory:"Formální trpný rod pro vyjádření obecného mínění bez uvedení zdroje: <b>It is said/believed/thought that…</b> nebo <b>He is said to be…</b>. Typické pro zprávy a formální text.",table:[["Vzorec","Příklad"],["It is + 3. tvar + that","It is believed that..."],["Podmět + is/was + 3. tvar + to + sloveso","He is said to be..."]],items:[["It ___ said that the economy is improving.","is",["is","was","has"],"Říká se, že ekonomika se zlepšuje."],["He is believed ___ have escaped by boat.","to",["to","that","for"],"Věří se, že uprchl na lodi."],["It ___ reported that the bridge will reopen soon.","is",["is","was","has"],"Uvádí se, že most se brzy znovu otevře."],["She is thought ___ be abroad right now.","to",["to","that","for"],"Myslí se, že je teď v zahraničí."],["It was widely ___ that he was innocent.","believed",["believed","belief","believing"],"Široce se věřilo, že je nevinný."],["The company is said ___ struggle financially.","to",["to","that","for"],"O firmě se říká, že finančně bojuje."],["It is ___ that prices will fall next year.","expected",["expected","expect","expecting"],"Očekává se, že ceny příští rok klesnou."],["He is rumoured ___ resign soon.","to",["to","that","for"],"Traduje se, že brzy odstoupí."],["It is thought ___ she left without saying goodbye.","that",["that","to","for"],"Myslí se, že odešla, aniž by se rozloučila."],["The number of victims is said ___ be much higher.","to",["to","that","for"],"Počet obětí je údajně mnohem vyšší."]]},
 {id:"c1g_emphasis",title:"Zdůraznění a předsazení",type:"grammar",theory:"V psaném a formálním projevu lze zdůraznit část věty jejím přesunem na začátek (fronting), což často vyžaduje inverzi: <b>So difficult was the exam that…</b>, <b>Little did he know…</b>, <b>Such was her surprise that…</b>",table:[["Výraz","Příklad"],["So + adj + that","So difficult was it that..."],["Little / Never","Little did he know..."],["Such + be + that","Such was her joy that..."]],items:[["So difficult ___ the exam that nobody passed.","was",["was","is","were"],"Zkouška byla tak těžká, že nikdo neuspěl."],["Little ___ he know what awaited him.","did",["did","does","do"],"Vůbec netušil, co ho čeká."],["Such ___ her joy that she started crying.","was",["was","is","were"],"Byla tak šťastná, že se rozplakala."],["Only later ___ we realise the truth.","did",["did","does","do"],"Teprve později jsme si uvědomili pravdu."],["Rarely ___ such dedication seen in young players.","is",["is","was","has"],"Málokdy je vidět taková oddanost u mladých hráčů."],["So loud ___ the music that we couldn't talk.","was",["was","is","were"],"Hudba byla tak hlasitá, že jsme se nemohli bavit."],["Not once ___ he complain about the pain.","did",["did","does","do"],"Ani jednou si nestěžoval na bolest."],["Never again ___ she trust him.","would",["would","will","did"],"Nikdy víc by mu nedůvěřovala."],["Such was the demand ___ tickets sold out in minutes.","that",["that","which","so"],"Poptávka byla taková, že lístky se vyprodaly během minut."],["Only when he apologised ___ she forgive him.","did",["did","does","do"],"Teprve když se omluvil, mu odpustila."]]},
 {id:"c1g_advmodal",title:"Pokročilá modální slovesa",type:"grammar",theory:"Jemné odstíny jistoty a lítosti v minulosti: <b>needn't have</b> (nebylo potřeba, ale stalo se), <b>could have</b> (bylo možné, ale nestalo se), <b>was/were to have</b> (mělo se stát, ale nestalo).",table:[["Forma","Význam"],["needn't have + 3. tvar","nebylo třeba"],["could have + 3. tvar","bylo možné"],["was/were to have + 3. tvar","mělo se stát"]],items:[["You ___ have worried, everything was fine.","needn't",["needn't","mustn't","shouldn't"],"Nemusel ses bát, všechno bylo v pořádku."],["He ___ have won, but he gave up too early.","could",["could","must","should"],"Mohl vyhrát, ale vzdal to moc brzy."],["We were ___ have met at six, but he was late.","to",["to","at","for"],"Měli jsme se sejít v šest, ale přišel pozdě."],["She ___ have called first before coming.","should",["should","could","needn't"],"Měla nejdřív zavolat, než přišla."],["You ___ have brought an umbrella, it wasn't raining.","needn't",["needn't","mustn't","shouldn't"],"Nemusel jsi brát deštník, nepršelo."],["They ___ have known about the plan all along.","must",["must","could","needn't"],"Museli o plánu vědět odjakživa."],["He ___ have taken the job, but he refused.","could",["could","must","needn't"],"Mohl tu práci vzít, ale odmítl."],["I ___ have told you earlier, I'm sorry.","should",["should","could","needn't"],"Měl jsem ti to říct dřív, promiň."],["The meeting was ___ have started at nine.","to",["to","at","for"],"Schůzka se měla začít v devět."],["You ___ have paid, it was free.","needn't",["needn't","mustn't","shouldn't"],"Nemusel jsi platit, bylo to zdarma."]]},
 {id:"c1g_subjunctive",title:"Konjunktiv",type:"grammar",theory:"Konjunktiv se používá po slovesech jako <b>suggest, recommend, insist, demand</b> a po výrazech <b>it's essential/important that</b>. Sloveso je v základním tvaru bez ohledu na osobu: I suggest he <b>be</b> present.",table:[["Sloveso/výraz","Příklad"],["suggest/recommend/insist that","...that he be present"],["it's essential/important that","...that she arrive on time"]],items:[["I suggest that he ___ present at the meeting.","be",["be","is","was"],"Navrhuji, aby byl přítomen na schůzce."],["It is essential that she ___ told immediately.","be",["be","is","was"],"Je nezbytné, aby jí to bylo řečeno ihned."],["The doctor recommended that he ___ more water.","drink",["drink","drinks","drank"],"Lékař doporučil, aby pil víc vody."],["They insisted that she ___ the report again.","rewrite",["rewrite","rewrites","rewrote"],"Trvali na tom, aby zprávu přepsala znovu."],["It's important that everyone ___ on time.","arrive",["arrive","arrives","arrived"],"Je důležité, aby všichni přišli včas."],["The judge demanded that the witness ___ the truth.","tell",["tell","tells","told"],"Soudce požadoval, aby svědek řekl pravdu."],["I propose that the meeting ___ postponed.","be",["be","is","was"],"Navrhuji, aby byla schůzka odložena."],["It's vital that we ___ this problem now.","solve",["solve","solves","solved"],"Je klíčové, abychom tento problém vyřešili teď."],["She insisted that he ___ home immediately.","go",["go","goes","went"],"Trvala na tom, aby šel domů okamžitě."],["The manager requested that everyone ___ silent.","remain",["remain","remains","remained"],"Manažer požádal, aby všichni zůstali potichu."]]}
